class Solution(object):
    def numDifferentIntegers(self, word):
        for char in 'abcdefghijklmnopqrstuvwxyz':
            word = word.replace(char, ' ')
        numbers = set()
        for num_str in word.split():
            numbers.add(int(num_str))
        return len(numbers)
